const rows = $input.all();

function parseBrief(value) {
  if (value == null || value === '') {
    return { technicalBrief: null, technicalBriefRaw: undefined };
  }

  if (typeof value === 'object') {
    return { technicalBrief: value, technicalBriefRaw: undefined };
  }

  const raw = String(value);
  try {
    const parsed = JSON.parse(raw);
    if (parsed && typeof parsed === 'object') {
      return { technicalBrief: parsed, technicalBriefRaw: raw };
    }
  } catch {
    return { technicalBrief: null, technicalBriefRaw: raw };
  }

  return { technicalBrief: null, technicalBriefRaw: raw };
}

const quotes = rows.map(({ json }, index) => {
  const brief = parseBrief(json.Technical_Brief_JSON ?? json.technicalBrief ?? json.technical_brief_json);

  return {
    id: json.leadId || json.id || json.Lead_ID || `lead-${index + 1}`,
    leadId: json.leadId || json.id || json.Lead_ID || `lead-${index + 1}`,
    nombre: json.nombre || json.name || json.Nombre || 'Sin nombre',
    empresa: json.empresa || json.company || json.Empresa || 'Empresa no especificada',
    email: json.email || json.Prospect_Email || json.Email || '',
    servicio: json.servicio || json.service || json.Servicio || 'Sin servicio',
    monto: json.monto || json.amount || json.Monto || '$0',
    industria: json.industria || json.industry || json.Industria || 'General',
    estado: json.estado || json.Estado || json.status || 'Pendiente',
    briefUrl: json.Brief_URL || json.briefUrl || '',
    briefToken: json.Brief_Token || json.briefToken || '',
    technicalBrief: brief.technicalBrief,
    technicalBriefRaw: brief.technicalBriefRaw,
    briefCompletedAt: json.Brief_Completed_At || json.briefCompletedAt || '',
    clientDashboardUrl: json.Client_Dashboard_URL || json.clientDashboardUrl || json.dashboardUrl || '',
    quoteDocumentId: json.Quote_Document_Id || json.quoteDocumentId || '',
    quotePdfUrl: json.Quote_PDF_URL || json.quotePdfUrl || '',
    quoteStatus: json.Quote_Status || json.quoteStatus || '',
    quoteGeneratedAt: json.Quote_Generated_At || json.quoteGeneratedAt || '',
    quoteApprovedAt: json.Quote_Approved_At || json.quoteApprovedAt || '',
    quoteLastFeedback: json.Quote_Last_Feedback || json.quoteLastFeedback || '',
    contractUrl: json.Contract_URL || json.contractUrl || '',
    contractGeneratedAt: json.Contract_Generated_At || json.contractGeneratedAt || ''
  };
});

return [{ json: { quotes } }];
